import React, { useEffect, useState } from 'react';
import { collection, doc, getDocs } from 'firebase/firestore';
import { db } from './firebase'; // adjust this path if needed

const Dashboard = ({ shopId }) => {
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchRequests = async () => {
      try {
        const requestsRef = collection(doc(db, 'shopkeepers', shopId), 'print_requests');
        const querySnapshot = await getDocs(requestsRef);
        const requestsData = querySnapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data(),
        }));
        setRequests(requestsData);
        setLoading(false);
      } catch (error) {
        console.error("Error fetching print requests:", error);
      }
    };

    fetchRequests();
  }, [shopId]);

  if (loading) return <div>Loading...</div>;

  return (
    <div style={{ padding: '30px', fontFamily: 'Arial' }}>
      <h2>Print Requests Dashboard</h2>
      {requests.length === 0 ? (
        <p>No print requests available.</p>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
          {requests.map(request => (
            <div
              key={request.id}
              style={{
                border: '1px solid #ccc',
                borderRadius: '10px',
                padding: '20px',
                background: '#f9f9f9',
              }}
            >
              <h4>{request.fileName || 'No File Name'}</h4>
              <a href={request.fileUrl} target="_blank" rel="noopener noreferrer">
                View File
              </a>
              <p><strong>Binding:</strong> {request.binding}</p>
              <p><strong>Punch:</strong> {request.punch}</p>
              <p><strong>Staple:</strong> {request.staple}</p>
              <p><strong>Pages:</strong> {request.pages || 'N/A'}</p>
              <p><strong>Copies:</strong> {request.copies || 'N/A'}</p>
              <p><strong>Color:</strong> {request.color || 'N/A'}</p>
              <p><strong>Print Type:</strong> {request.printType || 'N/A'}</p>
              <p><strong>Status:</strong> {request.status}</p>
              <p><strong>Total Price:</strong> ₹{request.price ?? 'Not Set'}</p>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default Dashboard;
